import { tool } from "@opencode-ai/plugin"

function filterDiffByLines(diff: string, targetLines: Set<number>): string | null {
  const lines = diff.split("\n")
  const output: string[] = []
  const hunks: string[] = []

  let i = 0

  // Collect header lines (diff --git, index, ---, +++)
  while (i < lines.length && !lines[i].startsWith("@@")) {
    const line = lines[i]
    if (
      line.startsWith("diff --git") ||
      line.startsWith("index") ||
      line.startsWith("---") ||
      line.startsWith("+++")
    ) {
      output.push(line)
    }
    i++
  }

  // Process hunks
  while (i < lines.length) {
    const line = lines[i]

    if (!line.startsWith("@@")) {
      i++
      continue
    }

    // Parse hunk header: @@ -old_start,old_count +new_start,new_count @@
    const hunkMatch = line.match(/@@ -(\d+),?(\d*) \+(\d+),?(\d*) @@/)

    if (!hunkMatch) {
      i++
      continue
    }

    const oldStart = parseInt(hunkMatch[1])
    const newStart = parseInt(hunkMatch[3])

    i++ // Move past hunk header

    let currentNewLine = newStart
    let currentOldLine = oldStart

    // Process hunk lines
    while (i < lines.length && !lines[i].startsWith("@@") && !lines[i].startsWith("diff --git")) {
      const hunkLine = lines[i]

      if (hunkLine.startsWith("+")) {
        // Addition - check if this line number is in our target set
        if (targetLines.has(currentNewLine)) {
          hunks.push(`@@ -${currentOldLine},0 +${currentNewLine} @@`)
          hunks.push(hunkLine)
        }
        currentNewLine++
      } else if (hunkLine.startsWith("-")) {
        // Deletion - check if we want to stage deletion at this position
        if (targetLines.has(currentNewLine)) {
          hunks.push(`@@ -${currentOldLine} +${currentNewLine},0 @@`)
          hunks.push(hunkLine)
        }
        currentOldLine++
      } else if (hunkLine.startsWith(" ")) {
        // Context line - both files advance
        currentNewLine++
        currentOldLine++
      }

      i++
    }
  }

  if (hunks.length === 0) {
    return null
  }

  // Combine header and hunks
  return [...output, ...hunks].join("\n") + "\n"
}

export default tool({
  description: "Stage specific lines of a file in git",
  args: {
    file: tool.schema.string().describe("Relative path to the file to stage"),
    lines: tool.schema
      .array(tool.schema.int().describe("The line number to stage"))
      .describe("List of line numbers to stage"),
  },
  async execute(args) {
    const diff = await Bun.$`git diff --unified=0 --no-color -- ${args.file}`.text()
    if (!diff.trim()) {
      return `No changes to stage in ${args.file}`
    }

    const filteredPatch = filterDiffByLines(diff, new Set(args.lines))
    if (!filteredPatch) {
      return `No matching lines found in diff for lines: ${args.lines.join(", ")}`
    }

    return await Bun.$`echo ${filteredPatch} | git apply --cached --unidiff-zero`.text()
  },
})

