import { tool } from "@opencode-ai/plugin"

const PR_FIELDS = [
  "number",
  "additions",
  "baseRefName",
  "body",
  "changedFiles",
  "comments",
  "deletions",
  "headRefName",
  "mergeStateStatus",
  "state",
  "statusCheckRollup",
  "title",
  "updatedAt",
  "url",
]

interface ReviewCommentsResponse {
  data: {
    repository: {
      pullRequest: {
        reviewThreads: {
          nodes: ReviewThread[]
        }
      }
    }
  }
}

interface ReviewThread {
  isOutdated: boolean
  isResolved: boolean
  path: string
  line: number
  comments: {
    nodes: Comment[]
  }
}

interface Comment {
  author: {
    login: string
  }
  body: string
}

const reviewCommentsQuery = /* graphql */ `
  query QueryGetReviewComments($prNumber: Int!) {
    repository(owner: "everii-Group", name: "mocoapp") {
      pullRequest(number: $prNumber) {
        reviewThreads(first: 100) {
          nodes {
            isOutdated
            isResolved
            path
            line
            comments(first: 50) {
              nodes {
                author { login }
                body
              }
            }
          }
        }
      }
    }
  }
`

export default tool({
  description: "View GitHub pull request details and diff using the gh CLI",
  args: {
    pr: tool.schema
      .string()
      .optional()
      .default("")
      .describe("The pull request number, URL, or branch. Default: the current branch name."),
    includeDiff: tool.schema
      .boolean()
      .optional()
      .default(true)
      .describe("Whether to include the diff output. Default: true"),
  },
  async execute(args) {
    const summary = await Bun.$`gh pr view ${args.pr} --json ${PR_FIELDS.join(",")}`
      .nothrow()
      .json()

    const reviewComments: ReviewCommentsResponse =
      await Bun.$`gh api graphql -f query=${reviewCommentsQuery} -F prNumber=${summary.number}`.json()

    summary.reviewComments = reviewComments.data.repository.pullRequest.reviewThreads.nodes.filter(
      ({ isOutdated, isResolved }) => !isOutdated && !isResolved,
    )

    if (!args.includeDiff) {
      return JSON.stringify(summary)
    }

    const diff = await Bun.$`gh pr diff ${args.pr}`.nothrow().text()

    return [JSON.stringify(summary), diff].join("\n\n")
  },
})

