        lines.append(f"- {skill['name']}: {desc}")
    lines.append("")
    lines.append(f"Load with: /{plugin}:{relevant[0]['name']}  (replace skill name as needed)")
    lines.append("</convention-skills>")
    return "\n".join(lines)

